import{_ as o,o as s,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse(`{"title":"Sandbox vs Tool Policy vs Elevated","description":"","frontmatter":{"title":"Sandbox vs Tool Policy vs Elevated","summary":"Why a tool is blocked: sandbox runtime, tool allow/deny policy, and elevated exec gates","read_when":"You hit 'sandbox jail' or see a tool/elevated refusal and want the exact config key to change.","status":"active"},"headers":[],"relativePath":"gateway/sandbox-vs-tool-policy-vs-elevated.md","filePath":"gateway/sandbox-vs-tool-policy-vs-elevated.md","lastUpdated":1771906665000}`),l={name:"gateway/sandbox-vs-tool-policy-vs-elevated.md"};function n(t,e,d,c,r,p){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="sandbox-vs-tool-policy-vs-elevated" tabindex="-1"><a class="header-anchor" href="#sandbox-vs-tool-policy-vs-elevated">#</a> Sandbox vs Tool Policy vs Elevated</h1><p>OpenSoul has three related (but different) controls:</p><ol><li><strong>Sandbox</strong> (<code>agents.defaults.sandbox.*</code> / <code>agents.list[].sandbox.*</code>) decides <strong>where tools run</strong> (Docker vs host).</li><li><strong>Tool policy</strong> (<code>tools.*</code>, <code>tools.sandbox.tools.*</code>, <code>agents.list[].tools.*</code>) decides <strong>which tools are available/allowed</strong>.</li><li><strong>Elevated</strong> (<code>tools.elevated.*</code>, <code>agents.list[].tools.elevated.*</code>) is an <strong>exec-only escape hatch</strong> to run on the host when you’re sandboxed.</li></ol><h2 id="quick-debug" tabindex="-1"><a class="header-anchor" href="#quick-debug">#</a> Quick debug</h2><p>Use the inspector to see what OpenSoul is <em>actually</em> doing:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent:main:main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>It prints:</p><ul><li>effective sandbox mode/scope/workspace access</li><li>whether the session is currently sandboxed (main vs non-main)</li><li>effective sandbox tool allow/deny (and whether it came from agent/global/default)</li><li>elevated gates and fix-it key paths</li></ul><h2 id="sandbox-where-tools-run" tabindex="-1"><a class="header-anchor" href="#sandbox-where-tools-run">#</a> Sandbox: where tools run</h2><p>Sandboxing is controlled by <code>agents.defaults.sandbox.mode</code>:</p><ul><li><code>&quot;off&quot;</code>: everything runs on the host.</li><li><code>&quot;non-main&quot;</code>: only non-main sessions are sandboxed (common “surprise” for groups/channels).</li><li><code>&quot;all&quot;</code>: everything is sandboxed.</li></ul><p>See <a href="/docs/gateway/sandboxing">Sandboxing</a> for the full matrix (scope, workspace mounts, images).</p><h3 id="bind-mounts-security-quick-check" tabindex="-1"><a class="header-anchor" href="#bind-mounts-security-quick-check">#</a> Bind mounts (security quick check)</h3><ul><li><code>docker.binds</code> <em>pierces</em> the sandbox filesystem: whatever you mount is visible inside the container with the mode you set (<code>:ro</code> or <code>:rw</code>).</li><li>Default is read-write if you omit the mode; prefer <code>:ro</code> for source/secrets.</li><li><code>scope: &quot;shared&quot;</code> ignores per-agent binds (only global binds apply).</li><li>Binding <code>/var/run/docker.sock</code> effectively hands host control to the sandbox; only do this intentionally.</li><li>Workspace access (<code>workspaceAccess: &quot;ro&quot;</code>/<code>&quot;rw&quot;</code>) is independent of bind modes.</li></ul><h2 id="tool-policy-which-tools-exist-are-callable" tabindex="-1"><a class="header-anchor" href="#tool-policy-which-tools-exist-are-callable">#</a> Tool policy: which tools exist/are callable</h2><p>Two layers matter:</p><ul><li><strong>Tool profile</strong>: <code>tools.profile</code> and <code>agents.list[].tools.profile</code> (base allowlist)</li><li><strong>Provider tool profile</strong>: <code>tools.byProvider[provider].profile</code> and <code>agents.list[].tools.byProvider[provider].profile</code></li><li><strong>Global/per-agent tool policy</strong>: <code>tools.allow</code>/<code>tools.deny</code> and <code>agents.list[].tools.allow</code>/<code>agents.list[].tools.deny</code></li><li><strong>Provider tool policy</strong>: <code>tools.byProvider[provider].allow/deny</code> and <code>agents.list[].tools.byProvider[provider].allow/deny</code></li><li><strong>Sandbox tool policy</strong> (only applies when sandboxed): <code>tools.sandbox.tools.allow</code>/<code>tools.sandbox.tools.deny</code> and <code>agents.list[].tools.sandbox.tools.*</code></li></ul><p>Rules of thumb:</p><ul><li><code>deny</code> always wins.</li><li>If <code>allow</code> is non-empty, everything else is treated as blocked.</li><li>Tool policy is the hard stop: <code>/exec</code> cannot override a denied <code>exec</code> tool.</li><li><code>/exec</code> only changes session defaults for authorized senders; it does not grant tool access. Provider tool keys accept either <code>provider</code> (e.g. <code>google-antigravity</code>) or <code>provider/model</code> (e.g. <code>openai/gpt-5.2</code>).</li></ul><h3 id="tool-groups-shorthands" tabindex="-1"><a class="header-anchor" href="#tool-groups-shorthands">#</a> Tool groups (shorthands)</h3><p>Tool policies (global, agent, sandbox) support <code>group:*</code> entries that expand to multiple tools:</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:runtime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:fs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:sessions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Available groups:</p><ul><li><code>group:runtime</code>: <code>exec</code>, <code>bash</code>, <code>process</code></li><li><code>group:fs</code>: <code>read</code>, <code>write</code>, <code>edit</code>, <code>apply_patch</code></li><li><code>group:sessions</code>: <code>sessions_list</code>, <code>sessions_history</code>, <code>sessions_send</code>, <code>sessions_spawn</code>, <code>session_status</code></li><li><code>group:memory</code>: <code>memory_search</code>, <code>memory_get</code></li><li><code>group:ui</code>: <code>browser</code>, <code>canvas</code></li><li><code>group:automation</code>: <code>cron</code>, <code>gateway</code></li><li><code>group:messaging</code>: <code>message</code></li><li><code>group:nodes</code>: <code>nodes</code></li><li><code>group:opensoul</code>: all built-in OpenSoul tools (excludes provider plugins)</li></ul><h2 id="elevated-exec-only-run-on-host" tabindex="-1"><a class="header-anchor" href="#elevated-exec-only-run-on-host">#</a> Elevated: exec-only “run on host”</h2><p>Elevated does <strong>not</strong> grant extra tools; it only affects <code>exec</code>.</p><ul><li>If you’re sandboxed, <code>/elevated on</code> (or <code>exec</code> with <code>elevated: true</code>) runs on the host (approvals may still apply).</li><li>Use <code>/elevated full</code> to skip exec approvals for the session.</li><li>If you’re already running direct, elevated is effectively a no-op (still gated).</li><li>Elevated is <strong>not</strong> skill-scoped and does <strong>not</strong> override tool allow/deny.</li><li><code>/exec</code> is separate from elevated. It only adjusts per-session exec defaults for authorized senders.</li></ul><p>Gates:</p><ul><li>Enablement: <code>tools.elevated.enabled</code> (and optionally <code>agents.list[].tools.elevated.enabled</code>)</li><li>Sender allowlists: <code>tools.elevated.allowFrom.&lt;provider&gt;</code> (and optionally <code>agents.list[].tools.elevated.allowFrom.&lt;provider&gt;</code>)</li></ul><p>See <a href="/docs/tools/elevated">Elevated Mode</a>.</p><h2 id="common-sandbox-jail-fixes" tabindex="-1"><a class="header-anchor" href="#common-sandbox-jail-fixes">#</a> Common “sandbox jail” fixes</h2><h3 id="tool-x-blocked-by-sandbox-tool-policy" tabindex="-1"><a class="header-anchor" href="#tool-x-blocked-by-sandbox-tool-policy">#</a> “Tool X blocked by sandbox tool policy”</h3><p>Fix-it keys (pick one):</p><ul><li>Disable sandbox: <code>agents.defaults.sandbox.mode=off</code> (or per-agent <code>agents.list[].sandbox.mode=off</code>)</li><li>Allow the tool inside sandbox: <ul><li>remove it from <code>tools.sandbox.tools.deny</code> (or per-agent <code>agents.list[].tools.sandbox.tools.deny</code>)</li><li>or add it to <code>tools.sandbox.tools.allow</code> (or per-agent allow)</li></ul></li></ul><h3 id="i-thought-this-was-main-why-is-it-sandboxed" tabindex="-1"><a class="header-anchor" href="#i-thought-this-was-main-why-is-it-sandboxed">#</a> “I thought this was main, why is it sandboxed?”</h3><p>In <code>&quot;non-main&quot;</code> mode, group/channel keys are <em>not</em> main. Use the main session key (shown by <code>sandbox explain</code>) or switch mode to <code>&quot;off&quot;</code>.</p>`,36)])])}const g=o(l,[["render",n]]);export{u as __pageData,g as default};
